/// Parse a JSON operator matrix payload into an Operator.
/// Format: {"dim":3,"entries":[{"n":1,"d":1},{"n":0,"d":1},...]}
pub fn parse_operator_json(payload: &str) -> Option<Operator> {
    let v: serde_json::Value = serde_json::from_str(payload).ok()?;
    let dim = v.get("dim")?.as_u64()? as usize;
    let entries = v.get("entries")?.as_array()?;
    if entries.len() != dim * dim { return None; }

    let mut matrix = vec![vec![Q::zero(); dim]; dim];
    let mut matrix_inv = vec![vec![Q::zero(); dim]; dim]; // approximate inverse
    for (idx, entry) in entries.iter().enumerate() {
        let n = entry.get("n").or_else(|| entry.get("numer"))?.as_i64()?;
        let d = entry.get("d").or_else(|| entry.get("denom"))?.as_u64().unwrap_or(1).max(1);
        let row = idx / dim;
        let col = idx % dim;
        matrix[row][col] = Q::new(BigInt::from(n), BigInt::from(d));
    }
    // Simple inverse: for identity-like matrices, A^{-1} ≈ 2I - A
    for i in 0..dim { matrix_inv[i][i] = Q::new(BigInt::from(1), BigInt::from(1)); }

    Some(Operator { id: 100, matrix, matrix_inv, det_sign_positive: true })
}

