/// EXECUTE_STEP handler.
/// D.AGENT.6 K2A Channel 1: autonomous K-step using entity.kernel's operators.
pub fn execute_step(entity: &mut Entity, _payload: &str) -> String {
    let c_before = coherence_functional(&entity.delta);
    let result = entity.execute_k_step();
    match result {
        Ok(output) => {
            let c_after = coherence_functional(&entity.delta);
            let rcf = compute_rcf_hash(&entity.delta);
            if let Some(ref hash) = output.receipt_hash {
                let entry = SluiceEntry::from_k_step(
                    entity.k_index as u64, rcf, *hash,
                    entity.sluice_state.enc_u8(), output.sigma_enc, &output.t_k,
                );
                let _ = entity.sluice.append(&entry);
                // state is in binary: state_record.bin, entity.sluice.bin, receipts.bin
            }
            format!(
                "{{\"executed\":true,\"k_index\":{},\"coherence_delta\":\"{}\"}}\n",
                entity.k_index, &c_after - &c_before
            )
        }
        Err(ref e) => format!(
            "{{\"executed\":false,\"reason\":\"{:?}\",\"k_index\":{}}}\n",
            e, entity.k_index
        ),
    }
}

/// UPGRADE handler.
/// D.MEMBRANE.3: Kernel participates in its own upgrade.
/// Receives ConfigSpaceOperator, evaluates through MDC,
/// writes UpgradeReceipt, exits cleanly for binary swap.
/// Systemd restarts with new binary. AGENT_REENTRY re-derives.
pub fn upgrade(entity: &mut Entity, payload: &str) -> String {
    let v: serde_json::Value = serde_json::from_str(payload).unwrap_or_default();

    let modules_str = v.get("modules").and_then(|m| m.as_str()).unwrap_or("");
    let delta_tests = v.get("delta_tests").and_then(|d| d.as_i64()).unwrap_or(0) as i32;
    let version = v.get("version").and_then(|v| v.as_str()).unwrap_or("unknown");

    let modules: Vec<String> = modules_str.split(',')
        .filter(|s| !s.is_empty())
        .map(|s| s.trim().to_string())
        .collect();

    // MDC evaluation of the upgrade
    let config_op = mdc::ConfigSpaceOperator {
        modules_changed: modules.clone(),
        delta_tests,
        predicted_coherence_impact: Q::zero(),
        version_tag: version.to_string(),
    };
    let registered = &["engine", "sampler", "coordinator", "mdc", "irs",
        "matrix", "gradient", "agent", "ledger", "rcf", "constants",
        "boot", "sluice_log", "mesh", "consensus", "fold", "operators",
        "credential", "ingress", "signing", "chain", "sim", "training"];
    let stasis_threshold = Q::new(BigInt::from(1), BigInt::from(2));
    let (mdc_result, tier) = mdc::evaluate_upgrade(&config_op, registered, &stasis_threshold);

    if tier >= 3 {
        // Blocked — Principal required
        format!(
            "{{\"upgrade\":\"blocked\",\"tier\":{},\"entropy\":\"{}/{}\",\"winner\":\"{:?}\",\"k_index\":{}}}\n",
            tier, mdc_result.entropy.numer(), mdc_result.entropy.denom(),
            mdc_result.winner, entity.k_index
        )
    } else {
        // Approved — write receipt, signal ready, exit for swap
        let receipt = saios_kernel_v2::ledger::UpgradeReceipt::new(
            &[0u8; 32], version, modules,
            0, delta_tests.unsigned_abs(), entity.k_index as u64,
        );

        // Write receipt to upgrades dir
        let upgrades_dir = entity.dir.join("upgrades");
        let _ = fs::create_dir_all(&upgrades_dir);
        let receipt_path = upgrades_dir.join(format!("upgrade_{}.json", version));
        if let Ok(json) = serde_json::to_string_pretty(&serde_json::json!({
            "receipt_id": receipt.receipt_id.iter().map(|b| format!("{b:02x}")).collect::<String>(),
            "kernel_version": receipt.kernel_version,
            "modules_changed": receipt.modules_changed,
            "test_count_after": receipt.test_count_after,
            "tier": tier,
            "k_at_upgrade": receipt.k_at_upgrade,
        })) {
            let _ = fs::write(&receipt_path, json);
        }

        // state is in binary: state_record.bin, entity.sluice.bin, receipts.bin

        format!(
            "{{\"upgrade\":\"approved\",\"tier\":{},\"version\":\"{}\",\"receipt\":\"{}\",\"action\":\"exit_for_swap\",\"k_index\":{}}}\n",
            tier, version,
            receipt.receipt_id.iter().map(|b| format!("{b:02x}")).collect::<String>(),
            entity.k_index
        )
    }
}

